/* ─── SCORE LABELS ────────────────────────────────────────────────────────── */
const getScoreLabel = (s) => {
  if (s >= 9) return { label:"ELITE",      color:B.gold,    emoji:"🔥" };
  if (s >= 7) return { label:"SOLID",      color:"#22C55E", emoji:"💪" };
  if (s >= 5) return { label:"DEVELOPING", color:"#38BDF8", emoji:"📈" };
  return             { label:"NEEDS WORK", color:B.red,     emoji:"🎯" };
};

/* ─── AUDIO ENGINE ────────────────────────────────────────────────────────── */
let _audio = null;
function stopAudio() {
  if (_audio) { try { _audio.pause(); } catch {} _audio = null; }
  try { if (window.speechSynthesis) window.speechSynthesis.cancel(); } catch {}
}
async function speakEL(text, apiKey, voiceId, onStart, onEnd) {
  stopAudio(); if (onStart) onStart();
  try {
    const res = await fetch(`https://api.elevenlabs.io/v1/text-to-speech/${voiceId}`, {
      method:"POST",
      headers:{ "xi-api-key":apiKey, "Content-Type":"application/json" },
      body:JSON.stringify({ text, model_id:"eleven_turbo_v2_5", voice_settings:{ stability:0.5, similarity_boost:0.75 } }),
    });
    if (!res.ok) {
      const errText = await res.text();
      console.error(`ElevenLabs error ${res.status}:`, errText);
      if (onEnd) onEnd();
      return;
    }
    const blob = await res.blob();
    const url = URL.createObjectURL(blob);
    const audio = new Audio(url);
    _audio = audio;
    audio.onended = () => { _audio=null; URL.revokeObjectURL(url); if (onEnd) onEnd(); };
    audio.onerror = (e) => { console.error("Audio playback error:", e); _audio=null; URL.revokeObjectURL(url); if (onEnd) onEnd(); };
    const playPromise = audio.play();
    if (playPromise !== undefined) {
      playPromise.catch(e => {
        console.error("Autoplay blocked:", e);
        _audio=null;
        if (onEnd) onEnd();
      });
    }
  } catch(e) { console.error("speakEL failed:", e); if (onEnd) onEnd(); }
}
function speakBrowser(text, onStart, onEnd) {
  if (!window.speechSynthesis) { if (onEnd) onEnd(); return; }
  stopAudio(); if (onStart) onStart();
  const u = new SpeechSynthesisUtterance(text);
  u.rate=0.92; u.pitch=0.95; u.volume=1;
  const v = window.speechSynthesis.getVoices().find(v => v.name.includes("Google US English") || v.lang==="en-US");
  if (v) u.voice = v;
  u.onend = () => { if (onEnd) onEnd(); };
  window.speechSynthesis.speak(u);
}

/* ─── CLAUDE EVAL ─────────────────────────────────────────────────────────── */
async function evalResponse({ objection, objective, benchmark, agentResponse }) {
  const FALLBACK = {
    score: 5,
    headline: "Scoring engine unavailable — check your API key.",
    whatWorked: "Your response was recorded.",
    whatToImprove: "Ensure public/config.js has your Anthropic key and redeploy.",
    coachingTip: "Visit console.anthropic.com to verify your key is active."
  };
  try {
    const anthropicKey = (window.__BTB_KEY__ || "").trim();
    if (!anthropicKey) return { ...FALLBACK, headline: "API key missing from config.js." };

    const prompt = `You are a real estate sales coach running "Beat The Bot" objection training.
Objection: "${objection}"
Objective: "${objective}"
Expert benchmark: "${benchmark}"
Agent response: "${agentResponse}"
Score 1-10 (10 = matches/exceeds benchmark). Reply ONLY with JSON, no markdown:
{"score":<1-10>,"headline":"<punchy one sentence>","whatWorked":"<1-2 sentences>","whatToImprove":"<1-2 sentences>","coachingTip":"<one actionable phrase>"}`;

    const res = await fetch("https://api.anthropic.com/v1/messages", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "x-api-key": anthropicKey,
        "anthropic-version": "2023-06-01",
        "anthropic-dangerous-direct-browser-access": "true"
      },
      body: JSON.stringify({ model: "claude-sonnet-4-20250514", max_tokens: 600, messages: [{ role: "user", content: prompt }] }),
    });

    const data = await res.json();

    if (!res.ok) {
      console.error("Anthropic API error:", res.status, data);
      return { ...FALLBACK, headline: `API error ${res.status}: ${data?.error?.message || "check your key"}` };
    }

    const text = data.content?.[0]?.text || "";
    if (!text) return FALLBACK;

    const parsed = JSON.parse(text.replace(/```json|```/g, "").trim());
    return (parsed.score && parsed.headline) ? parsed : FALLBACK;

  } catch(e) {
    console.error("evalResponse failed:", e);
    return FALLBACK;
  }
}

/* ─── SETTINGS MODAL (API key only) ─────────────────────────────────────────── */
function SettingsModal({ apiKey, setApiKey, onClose }) {
  const [localKey, setLocalKey] = useState(apiKey);
  const [showKey,  setShowKey]  = useState(false);
  const [keyErr,   setKeyErr]   = useState("");
  const [saved,    setSaved]    = useState(false);

  const handleSave = () => {
    if (!localKey.trim()) { setKeyErr("API key is required."); return; }
    setApiKey(localKey.trim());
    try { localStorage.setItem("btb_api_key", localKey.trim()); } catch {}
    setSaved(true); setTimeout(() => { setSaved(false); onClose(); }, 600);
  };

  return (
    <div style={{ position:"fixed", inset:0, background:"rgba(4,12,28,0.93)", zIndex:300, display:"flex", alignItems:"center", justifyContent:"center", padding:16 }}>
      <div style={{ background:B.dark, border:`1px solid ${rgba(B.gold,0.25)}`, borderRadius:16, width:"100%", maxWidth:460, padding:28, boxSizing:"border-box", fontFamily:B.font }}>
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:24 }}>
          <div>
            <div style={{ fontSize:10, letterSpacing:4, color:B.gold, marginBottom:5, fontWeight:700 }}>CONFIGURATION</div>
            <h2 style={{ margin:0, fontSize:20, fontWeight:900, color:B.white }}>Anthropic API Key</h2>
          </div>
          <button onClick={onClose} style={{ background:"none", border:"none", color:B.muted, cursor:"pointer", fontSize:22 }}>✕</button>
        </div>
        <div style={{ marginBottom:22 }}>
          <label style={{ fontSize:10, letterSpacing:3, color:B.muted, display:"block", marginBottom:8, fontWeight:700 }}>API KEY</label>
          <div style={{ position:"relative" }}>
            <input type={showKey?"text":"password"} value={localKey} onChange={e=>{setLocalKey(e.target.value);setKeyErr("");}} placeholder="sk-ant-..."
              style={{ width:"100%", boxSizing:"border-box", padding:"11px 42px 11px 13px", background:rgba(B.white,0.05), border:`1px solid ${keyErr?B.red:rgba(B.white,0.12)}`, borderRadius:8, color:B.white, fontSize:13, fontFamily:B.font, outline:"none" }}/>
            <button onClick={()=>setShowKey(p=>!p)} style={{ position:"absolute", right:11, top:"50%", transform:"translateY(-50%)", background:"none", border:"none", color:B.muted, cursor:"pointer", fontSize:15 }}>
              {showKey?"🙈":"👁️"}
            </button>
          </div>
          {keyErr
            ? <div style={{ marginTop:5, fontSize:11, color:B.red }}>{keyErr}</div>
            : <div style={{ marginTop:5, fontSize:11, color:"rgba(255,255,255,0.35)" }}>Your key is stored locally and never shared. Get it at <a href="https://console.anthropic.com" target="_blank" rel="noreferrer" style={{ color:B.gold }}>console.anthropic.com</a>.</div>}
        </div>
        <button onClick={handleSave} style={{ width:"100%", padding:"14px", background:saved?"#22C55E":B.red, border:"none", borderRadius:10, color:B.white, fontSize:14, fontWeight:800, cursor:"pointer", letterSpacing:2, fontFamily:B.font, transition:"background 0.3s" }}>
          {saved?"✓ SAVED!":"SAVE KEY"}
        </button>
      </div>
    </div>
  );
}


