/* ─── ROOT APP ────────────────────────────────────────────────────────────── */
export default function BeatTheBot() {
  const [screen,       setScreen]      = useState("home");
  const [pack,         setPack]        = useState(null);
  const [roundIdx,     setRoundIdx]    = useState(0);
  const [agentText,    setAgentText]   = useState("");
  const [isListening,  setIsListening] = useState(false);
  const [isSpeaking,   setIsSpeaking]  = useState(false);
  const [isEval,       setIsEval]      = useState(false);
  const [evaluation,   setEvaluation]  = useState(null);
  const [showBench,    setShowBench]   = useState(false);
  const [scores,       setScores]      = useState([]);
  const [botSpoken,    setBotSpoken]   = useState(false);
  const [micDenied,    setMicDenied]   = useState(false);
  const [showSettings, setShowSettings]= useState(false);
  const [apiKey,       setApiKey]      = useState("");
  // Voice IDs are hardcoded per pack — see CHALLENGER_VOICES and COACH_VOICE_ID constants
  const recRef = useRef(null);

  const round     = pack?.rounds[roundIdx];

  const avgScore  = scores.length ? Math.round(scores.reduce((a,b)=>a+b,0)/scores.length) : 0;
  const cleanText = agentText.replace(/\[…\]$/,"").trim();

  useEffect(() => {
    try {
      const k = localStorage.getItem("btb_api_key");
      if (k) setApiKey(k);
    } catch {}
  }, []);

  useEffect(() => {
    const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SR) return;
    const rec = new SR();
    rec.continuous=true; rec.interimResults=true; rec.lang="en-US";
    rec.onresult = (e) => {
      let fin="", int="";
      for (let i=e.resultIndex; i<e.results.length; i++) {
        if (e.results[i].isFinal) fin += e.results[i][0].transcript+" ";
        else int += e.results[i][0].transcript;
      }
      setAgentText(prev => { const base=prev.replace(/\[…\]$/,"").trimEnd(); return fin?(base+" "+fin).trim():(base+" "+int+"[…]").trim(); });
    };
    rec.onerror = (e) => { if(e.error==="not-allowed") setMicDenied(true); setIsListening(false); };
    rec.onend = () => setIsListening(false);
    recRef.current = rec;
    return () => stopAudio();
  }, []);

  const doSpeak = useCallback((text, cb, useCoachVoice = false) => {
    const elKey = (window.__EL_KEY__ || "").trim();
    const vid = useCoachVoice
      ? COACH_VOICE_ID
      : CHALLENGER_VOICES[pack?.id] || CHALLENGER_VOICES[1];
    if (elKey) speakEL(text, elKey, vid, ()=>setIsSpeaking(true), ()=>{ setIsSpeaking(false); if(cb)cb(); });
    else speakBrowser(text, ()=>setIsSpeaking(true), ()=>{ setIsSpeaking(false); if(cb)cb(); });
  }, [pack]);

  const speakObjection = useCallback(() => {
    if (!round) return;
    doSpeak(round.objection, () => setBotSpoken(true));
  }, [round, doSpeak]);

  const startListening = () => {
    if (!recRef.current) return;
    stopAudio(); setAgentText("");
    try { recRef.current.start(); setIsListening(true); } catch {}
  };
  const stopListening = () => {
    if (!recRef.current) return;
    recRef.current.stop(); setIsListening(false);
  };

  const handlePickPack = (p) => { setPack(p); setRoundIdx(0); setScores([]); setScreen("briefing"); };
  const handleStartRound = () => {
    setAgentText(""); setEvaluation(null); setShowBench(false); setBotSpoken(false);
    setScreen("round");
    // Note: audio triggered by explicit user tap on the round screen (autoplay policy)
  };
  const handleSubmit = async () => {
    if (!cleanText || cleanText.length<10) return;
    stopListening(); setIsEval(true);
    const result = await evalResponse({ objection:round.objection, objective:round.objective, benchmark:round.benchmark, agentResponse:cleanText });
    setEvaluation(result); setScores(prev=>[...prev, result.score]); setIsEval(false); setScreen("result");
    setTimeout(() => doSpeak(`Score: ${result.score} out of 10. ${result.headline} ${result.coachingTip}`, null, true), 400);
  };
  const handleNext = () => {
    const next = roundIdx+1;
    if (next >= pack.rounds.length) setScreen("packComplete");
    else { setRoundIdx(next); setScreen("briefing"); }
  };

  /* ── shared shell ── */
  const Shell = ({ children }) => (
    <div style={{ minHeight:"100vh", background:B.darker, color:B.white, fontFamily:B.font, position:"relative", overflow:"hidden" }}>
      {/* Subtle grid */}
      <div style={{ position:"fixed", inset:0, pointerEvents:"none", zIndex:0, backgroundImage:`linear-gradient(${rgba(B.navy,0.35)} 1px,transparent 1px),linear-gradient(90deg,${rgba(B.navy,0.35)} 1px,transparent 1px)`, backgroundSize:"56px 56px" }}/>
      {/* Top ERA red bar */}
      <div style={{ position:"fixed", top:0, left:0, right:0, height:4, background:B.red, zIndex:10 }}/>
      <div style={{ position:"relative", zIndex:1, maxWidth:880, margin:"0 auto", padding:"28px 18px" }}>
        {children}
      </div>
      {showSettings && <SettingsModal apiKey={apiKey} setApiKey={setApiKey} onClose={()=>setShowSettings(false)}/>}
    </div>
  );

  /* ═══════════════════════════════════════════════════════════════════════════
     HOME — REDESIGNED TITLE PAGE
  ═══════════════════════════════════════════════════════════════════════════ */
  if (screen === "home") return (
    <Shell>
      {/* ── NAV BAR ── */}
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:48, paddingTop:8 }}>
        <EraLogo size="md"/>
        <button onClick={()=>setShowSettings(true)} style={{ display:"flex", alignItems:"center", gap:7, background:rgba(B.white,0.05), border:`1px solid ${rgba(B.white,0.1)}`, borderRadius:8, padding:"8px 14px", color:B.muted, cursor:"pointer", fontSize:12, fontWeight:700, letterSpacing:1, fontFamily:B.font }}>
          ⚙️ <span>Settings</span>
        </button>
      </div>

      {/* ── HERO ── */}
      <div style={{ textAlign:"center", marginBottom:52 }}>
        {/* Red rule */}
        <div style={{ display:"flex", alignItems:"center", gap:16, marginBottom:28, justifyContent:"center" }}>
          <div style={{ height:2, width:60, background:`linear-gradient(to right, transparent, ${B.red})` }}/>
          <div style={{ fontSize:10, letterSpacing:6, color:B.red, fontWeight:700 }}>AGENT TRAINING PROGRAM</div>
          <div style={{ height:2, width:60, background:`linear-gradient(to left, transparent, ${B.red})` }}/>
        </div>

        {/* Main title */}
        <h1 style={{ fontSize:"clamp(52px,10vw,88px)", fontWeight:900, margin:0, lineHeight:0.95, letterSpacing:-3, fontFamily:B.font }}>
          <span style={{ color:B.white }}>BEAT</span><br/>
          <span style={{ color:B.red }}>THE</span>{" "}
          <span style={{ color:B.white }}>BOT</span>
        </h1>

        {/* Gold divider */}
        <div style={{ margin:"20px auto", width:80, height:3, background:B.gold, borderRadius:2 }}/>

        <p style={{ margin:"0 auto 24px", maxWidth:480, fontSize:15, color:B.muted, lineHeight:1.6, fontWeight:400 }}>
          AI-powered objection training for ERA Grizzard agents. Hear the objection live, respond out loud, and get instant coaching feedback.
        </p>

        {/* Voice badge */}
        <div style={{ display:"inline-flex", alignItems:"center", gap:8, background: apiKey?rgba(B.red,0.1):rgba(B.white,0.04), border:`1px solid ${apiKey?rgba(B.red,0.3):rgba(B.white,0.1)}`, borderRadius:20, padding:"7px 16px", fontSize:12, color: apiKey?"#fff":B.muted, fontWeight:600 }}>
          {apiKey ? "🎙️ ElevenLabs Voice · Active" : "🔊 Browser voice (ElevenLabs key not set in config.js)"}
          {!apiKey && (
            <button onClick={()=>setShowSettings(true)} style={{ marginLeft:6, background:B.red, border:"none", borderRadius:10, padding:"2px 10px", color:"#fff", fontSize:11, fontWeight:700, cursor:"pointer", fontFamily:B.font }}>
              CONNECT
            </button>
          )}
        </div>
      </div>

      {/* ── SECTION LABEL ── */}
      <div style={{ display:"flex", alignItems:"center", gap:12, marginBottom:16 }}>
        <div style={{ fontSize:10, letterSpacing:4, color:B.gold, fontWeight:700 }}>CHOOSE YOUR PACK</div>
        <div style={{ flex:1, height:1, background:rgba(B.gold,0.2) }}/>
        <div style={{ fontSize:11, color:B.muted }}>{GAME_PACKS.length} PACKS · 15 ROUNDS TOTAL</div>
      </div>

      {/* ── PACK GRID ── */}
      <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill,minmax(250px,1fr))", gap:14, marginBottom:32 }}>
        {GAME_PACKS.map((p, i) => (
          <button key={p.id} onClick={()=>handlePickPack(p)}
            style={{ background:`linear-gradient(135deg, ${rgba(p.color,0.08)}, ${rgba(B.navy,0.3)})`, border:`1px solid ${rgba(p.color,0.2)}`, borderTop:`3px solid ${p.color}`, borderRadius:12, padding:"18px 18px 16px", cursor:"pointer", textAlign:"left", transition:"all 0.2s", position:"relative", overflow:"hidden" }}
            onMouseEnter={e=>{ e.currentTarget.style.transform="translateY(-3px)"; e.currentTarget.style.borderColor=p.color; e.currentTarget.style.boxShadow=`0 8px 32px ${rgba(p.color,0.2)}`; }}
            onMouseLeave={e=>{ e.currentTarget.style.transform="translateY(0)"; e.currentTarget.style.borderColor=rgba(p.color,0.2); e.currentTarget.style.boxShadow="none"; }}
          >
            {/* Pack number watermark */}
            <div style={{ position:"absolute", top:8, right:14, fontSize:42, fontWeight:900, color:rgba(p.color,0.08), lineHeight:1, fontFamily:B.font }}>
              {String(i+1).padStart(2,"0")}
            </div>
            <div style={{ fontSize:26, marginBottom:9 }}>{p.icon}</div>
            <div style={{ fontSize:9, letterSpacing:3, color:p.color, marginBottom:4, fontWeight:700 }}>PACK {p.id}</div>
            <div style={{ fontSize:15, fontWeight:800, color:B.white, marginBottom:3, fontFamily:B.font }}>{p.title}</div>
            <div style={{ fontSize:12, color:B.muted, marginBottom:10 }}>{p.subtitle}</div>
            <div style={{ display:"flex", alignItems:"center", gap:6 }}>
              <div style={{ width:6, height:6, borderRadius:"50%", background:p.color }}/>
              <span style={{ fontSize:11, color:"rgba(255,255,255,0.35)" }}>3 ROUNDS</span>
            </div>
          </button>
        ))}
      </div>

      {/* ── HOW IT WORKS ── */}
      <div style={{ background:rgba(B.navy,0.25), border:`1px solid ${rgba(B.white,0.07)}`, borderRadius:12, padding:"18px 20px" }}>
        <div style={{ fontSize:10, letterSpacing:4, color:B.gold, marginBottom:12, fontWeight:700 }}>HOW IT WORKS</div>
        <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit,minmax(155px,1fr))", gap:14 }}>
          {[["01","Bot speaks the objection out loud — in character"],["02","You respond via mic or by typing"],["03","Claude scores your answer vs. the expert benchmark"],["04","Get targeted coaching feedback and replay"]].map(([n,t])=>(
            <div key={n} style={{ display:"flex", gap:8, alignItems:"flex-start" }}>
              <span style={{ color:B.red, fontSize:12, fontWeight:800, flexShrink:0, fontFamily:B.font }}>{n}</span>
              <span style={{ color:B.muted, fontSize:12, lineHeight:1.5 }}>{t}</span>
            </div>
          ))}
        </div>
      </div>

      {/* Bottom navy bar */}
      <div style={{ marginTop:32, borderTop:`1px solid ${rgba(B.white,0.06)}`, paddingTop:14, display:"flex", justifyContent:"space-between", alignItems:"center" }}>
        <div style={{ fontSize:11, color:"rgba(255,255,255,0.2)" }}>© ERA Grizzard Real Estate · Internal Training Tool</div>
        <div style={{ fontSize:11, color:"rgba(255,255,255,0.2)" }}>Powered by Claude + ElevenLabs</div>
      </div>
    </Shell>
  );

  /* ═══════════════════════════════════════════════════════════════════════════
     BRIEFING
  ═══════════════════════════════════════════════════════════════════════════ */
  if (screen === "briefing") return (
    <Shell>
      <div style={{ maxWidth:580, margin:"0 auto", paddingTop:20 }}>
        <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:28 }}>
          <EraLogo size="sm"/>
          <button onClick={()=>setScreen("home")} style={{ background:"none", border:"none", color:B.muted, cursor:"pointer", fontSize:12, letterSpacing:2, fontFamily:B.font, fontWeight:600 }}>← BACK</button>
        </div>

        {/* Progress */}
        <div style={{ display:"flex", gap:6, marginBottom:22 }}>
          {pack.rounds.map((_,i) => (
            <div key={i} style={{ flex:1, height:4, borderRadius:2, background: i<=roundIdx?pack.color:rgba(B.white,0.1) }}/>
          ))}
        </div>

        <div style={{ fontSize:10, letterSpacing:4, color:pack.color, marginBottom:5, fontWeight:700 }}>PACK {pack.id} · ROUND {round.round} OF {pack.rounds.length}</div>
        <h2 style={{ fontSize:26, fontWeight:900, margin:"0 0 22px", color:B.white, fontFamily:B.font }}>Incoming Objection</h2>

        <div style={{ display:"grid", gap:10, marginBottom:24 }}>
          <InfoCard label="PERSONA"        value={round.persona}   accent={pack.color} icon="👤"/>
          <InfoCard label="YOUR OBJECTIVE" value={round.objective} accent={pack.color} icon="🎯"/>
          <InfoCard label="VOICES" value="Challenger + Coach voices assigned for this pack" accent={pack.color} icon="🎙️"/>
        </div>

        <div style={{ background:rgba(pack.color,0.07), border:`1px solid ${rgba(pack.color,0.22)}`, borderRadius:12, padding:16, marginBottom:24 }}>
          <div style={{ fontSize:10, letterSpacing:3, color:pack.color, marginBottom:6, fontWeight:700 }}>GET READY</div>
          <div style={{ fontSize:13, color:B.muted, lineHeight:1.6 }}>The bot speaks the objection the moment the round starts. Respond with your mic or type it. Claude scores against the expert benchmark.</div>
        </div>

        <button onClick={handleStartRound} style={{ width:"100%", padding:"15px", background:B.red, border:"none", borderRadius:10, color:B.white, fontSize:14, fontWeight:800, cursor:"pointer", letterSpacing:2, fontFamily:B.font, boxShadow:`0 4px 20px ${rgba(B.red,0.35)}` }}>
          START ROUND {round.round} →
        </button>
      </div>
    </Shell>
  );

  /* ═══════════════════════════════════════════════════════════════════════════
     ACTIVE ROUND
  ═══════════════════════════════════════════════════════════════════════════ */
  if (screen === "round") return (
    <Shell>
      <div style={{ maxWidth:660, margin:"0 auto", paddingTop:8 }}>
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:18 }}>
          <EraLogo size="sm"/>
          <div style={{ textAlign:"right" }}>
            <div style={{ fontSize:10, letterSpacing:3, color:pack.color, fontWeight:700 }}>PACK {pack.id} · ROUND {round.round}</div>
            <div style={{ fontSize:11, color:B.muted }}>{round.persona}</div>
          </div>
        </div>

        {/* Bot card */}
        <div style={{ background:rgba(B.navy,0.3), border:`1px solid ${rgba(B.white,0.1)}`, borderRadius:14, padding:22, marginBottom:16 }}>
          <div style={{ display:"flex", gap:12, alignItems:"flex-start" }}>
            <div style={{ width:46, height:46, borderRadius:"50%", background: isSpeaking?B.red:rgba(B.white,0.07), display:"flex", alignItems:"center", justifyContent:"center", fontSize:20, flexShrink:0, transition:"all 0.3s", boxShadow: isSpeaking?`0 0 24px ${rgba(B.red,0.6)}`:"none" }}>🤖</div>
            <div style={{ flex:1 }}>
              <div style={{ fontSize:10, letterSpacing:3, color: isSpeaking?B.red:B.muted, marginBottom:6, fontWeight:700 }}>
                {isSpeaking?"● SPEAKING…":botSpoken?"✓ OBJECTION DELIVERED":"READY TO DELIVER OBJECTION"}
              </div>
              <div style={{ fontSize:15, color:"#e0e0e0", lineHeight:1.7, fontStyle:"italic" }}>"{round.objection}"</div>
            </div>
          </div>
          {!botSpoken ? (
            <button onClick={speakObjection} disabled={isSpeaking} style={{ marginTop:12, padding:"10px 20px", background:isSpeaking?rgba(B.red,0.3):B.red, border:"none", borderRadius:8, color:B.white, cursor:isSpeaking?"not-allowed":"pointer", fontSize:13, fontWeight:700, letterSpacing:1, fontFamily:B.font, boxShadow:isSpeaking?`0 0 18px ${rgba(B.red,0.4)}`:`0 4px 14px ${rgba(B.red,0.35)}` }}>
              {isSpeaking ? "🔊 Playing objection…" : "▶ PLAY OBJECTION"}
            </button>
          ) : (
            <button onClick={speakObjection} disabled={isSpeaking} style={{ marginTop:12, background:rgba(B.white,0.05), border:`1px solid ${rgba(B.white,0.1)}`, borderRadius:6, color: isSpeaking?rgba(B.white,0.25):B.muted, cursor:isSpeaking?"not-allowed":"pointer", padding:"5px 13px", fontSize:11, letterSpacing:1, fontFamily:B.font }}>
              {isSpeaking?"🔊 Playing…":"🔊 Replay Objection"}
            </button>
          )}
        </div>

        {/* Agent input */}
        <div style={{ background:rgba(B.navy,0.2), border:`2px solid ${isListening?B.red:rgba(B.white,0.08)}`, borderRadius:14, padding:18, marginBottom:13, transition:"border-color 0.25s", boxShadow:isListening?`0 0 0 3px ${rgba(B.red,0.15)}`:"none" }}>
          <div style={{ fontSize:10, letterSpacing:3, color:isListening?B.red:B.muted, marginBottom:8, fontWeight:700 }}>
            {isListening?"● RECORDING YOUR RESPONSE…":"YOUR RESPONSE"}
          </div>
          <textarea value={agentText} onChange={e=>setAgentText(e.target.value)} placeholder="Speak into your mic, or type your response here…"
            style={{ width:"100%", minHeight:110, background:"transparent", border:"none", color:B.white, fontSize:14, lineHeight:1.7, resize:"vertical", outline:"none", fontFamily:B.font, boxSizing:"border-box" }}/>
          <div style={{ fontSize:10, color:rgba(B.white,0.25), marginTop:2 }}>{cleanText.split(" ").filter(Boolean).length} words</div>
        </div>

        <div style={{ display:"flex", gap:10 }}>
          <button onClick={isListening?stopListening:startListening}
            style={{ flex:1, padding:"13px", borderRadius:10, background:isListening?B.red:rgba(B.white,0.06), border:`1px solid ${isListening?B.red:rgba(B.white,0.11)}`, color:B.white, cursor:"pointer", fontSize:13, fontWeight:700, letterSpacing:1, fontFamily:B.font, transition:"all 0.2s", boxShadow:isListening?`0 0 20px ${rgba(B.red,0.4)}`:"none" }}>
            {isListening?"⏹ STOP RECORDING":"🎤 RECORD RESPONSE"}
          </button>
          <button onClick={handleSubmit} disabled={cleanText.length<10||isEval}
            style={{ flex:1, padding:"13px", borderRadius:10, background:cleanText.length>=10?B.red:rgba(B.white,0.04), border:"none", color:cleanText.length>=10?B.white:rgba(B.white,0.25), cursor:cleanText.length>=10?"pointer":"not-allowed", fontSize:13, fontWeight:800, letterSpacing:1, fontFamily:B.font, transition:"all 0.2s", boxShadow:cleanText.length>=10?`0 4px 18px ${rgba(B.red,0.3)}`:"none" }}>
            {isEval?"⏳ EVALUATING…":"SUBMIT FOR SCORING →"}
          </button>
        </div>
        {micDenied && <div style={{ marginTop:9, padding:9, background:rgba(B.red,0.08), border:`1px solid ${rgba(B.red,0.25)}`, borderRadius:8, fontSize:12, color:B.red, fontFamily:B.font }}>⚠️ Mic access denied. Allow mic in your browser settings or type above.</div>}
      </div>
    </Shell>
  );

  /* ═══════════════════════════════════════════════════════════════════════════
     RESULT
  ═══════════════════════════════════════════════════════════════════════════ */
  if (screen === "result" && evaluation) {
    const si = getScoreLabel(evaluation.score);
    const isLast = roundIdx === pack.rounds.length-1;
    return (
      <Shell>
        <div style={{ maxWidth:620, margin:"0 auto", paddingTop:8 }}>
          <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:20 }}>
            <EraLogo size="sm"/>
            <div style={{ fontSize:10, letterSpacing:3, color:pack.color, fontWeight:700 }}>ROUND {round.round} COMPLETE</div>
          </div>

          {/* Score hero */}
          <div style={{ textAlign:"center", marginBottom:20, padding:"28px 20px", background:`linear-gradient(135deg,${rgba(si.color,0.1)},${rgba(B.navy,0.4)})`, border:`1px solid ${rgba(si.color,0.25)}`, borderRadius:16, position:"relative", overflow:"hidden" }}>
            <div style={{ position:"absolute", top:0, left:0, right:0, height:3, background:si.color }}/>
            <div style={{ fontSize:72, fontWeight:900, color:si.color, lineHeight:1, fontFamily:B.font }}>
              {evaluation.score ?? "?"}<span style={{ fontSize:28, color:rgba(B.white,0.25), fontWeight:400 }}>/10</span>
            </div>
            <div style={{ fontSize:18, letterSpacing:5, fontWeight:800, color:si.color, marginTop:4 }}>{si.emoji} {si.label}</div>
            <div style={{ marginTop:10, fontSize:15, color:"#ccc", lineHeight:1.5, fontStyle:"italic" }}>"{evaluation.headline}"</div>
          </div>

          <div style={{ display:"grid", gap:9, marginBottom:14 }}>
            <FeedbackCard icon="✅" label="WHAT WORKED"  text={evaluation.whatWorked}    color="#22C55E"/>
            <FeedbackCard icon="🎯" label="BIGGEST GAP"  text={evaluation.whatToImprove} color={B.gold}/>
            <FeedbackCard icon="💡" label="COACHING TIP" text={evaluation.coachingTip}   color="#38BDF8"/>
          </div>

          <button onClick={()=>setShowBench(p=>!p)} style={{ width:"100%", padding:"11px", background:rgba(B.white,0.03), border:`1px solid ${rgba(B.white,0.09)}`, borderRadius:9, color:B.muted, cursor:"pointer", fontSize:12, letterSpacing:2, fontFamily:B.font, fontWeight:600, marginBottom:9 }}>
            {showBench?"▲ HIDE BENCHMARK":"▼ SHOW EXPERT BENCHMARK"}
          </button>
          {showBench && (
            <div style={{ background:rgba(B.navy,0.35), border:`1px solid ${rgba(B.white,0.09)}`, borderLeft:`3px solid ${B.gold}`, borderRadius:"0 9px 9px 0", padding:16, marginBottom:12 }}>
              <div style={{ fontSize:10, letterSpacing:3, color:B.gold, marginBottom:7, fontWeight:700 }}>EXPERT BENCHMARK</div>
              <div style={{ fontSize:13, color:"#bbb", lineHeight:1.7 }}>{round.benchmark}</div>
              <button onClick={()=>doSpeak(round.benchmark, null, true)} style={{ marginTop:10, background:"none", border:`1px solid ${rgba(B.white,0.1)}`, borderRadius:6, color:B.muted, cursor:"pointer", padding:"5px 12px", fontSize:11, fontFamily:B.font }}>
                🔊 Listen to Benchmark
              </button>
            </div>
          )}
          <button onClick={handleNext} style={{ width:"100%", padding:"15px", background:B.red, border:"none", borderRadius:10, color:B.white, fontSize:14, fontWeight:800, cursor:"pointer", letterSpacing:2, fontFamily:B.font, boxShadow:`0 4px 20px ${rgba(B.red,0.3)}` }}>
            {isLast?"SEE FINAL RESULTS →":"NEXT ROUND →"}
          </button>
        </div>
      </Shell>
    );
  }

  /* ═══════════════════════════════════════════════════════════════════════════
     PACK COMPLETE
  ═══════════════════════════════════════════════════════════════════════════ */
  if (screen === "packComplete") {
    const si = getScoreLabel(avgScore);
    return (
      <Shell>
        <div style={{ maxWidth:500, margin:"0 auto", paddingTop:28, textAlign:"center" }}>
          <div style={{ display:"flex", justifyContent:"center", marginBottom:28 }}><EraLogo size="md"/></div>

          {/* Gold rule */}
          <div style={{ width:60, height:3, background:B.gold, borderRadius:2, margin:"0 auto 20px" }}/>

          <div style={{ fontSize:11, letterSpacing:5, color:pack.color, marginBottom:8, fontWeight:700 }}>PACK {pack.id} COMPLETE</div>
          <div style={{ fontSize:44, marginBottom:6 }}>{pack.icon}</div>
          <h2 style={{ fontSize:28, fontWeight:900, margin:"0 0 4px", color:B.white, fontFamily:B.font }}>{pack.title}</h2>
          <div style={{ fontSize:12, color:B.muted, marginBottom:24 }}>Final Report Card</div>

          <div style={{ background:`linear-gradient(135deg,${rgba(si.color,0.1)},${rgba(B.navy,0.5)})`, border:`1px solid ${rgba(si.color,0.3)}`, borderTop:`3px solid ${si.color}`, borderRadius:16, padding:"26px 20px", marginBottom:22 }}>
            <div style={{ fontSize:60, fontWeight:900, color:si.color, fontFamily:B.font }}>{avgScore}<span style={{ fontSize:22, color:rgba(B.white,0.25) }}>/10</span></div>
            <div style={{ fontSize:16, letterSpacing:4, color:si.color, marginTop:4, fontWeight:700 }}>{si.emoji} {si.label}</div>
            <div style={{ marginTop:16, display:"flex", justifyContent:"center", gap:18 }}>
              {scores.map((s,i) => { const ss=getScoreLabel(s); return (
                <div key={i} style={{ textAlign:"center" }}>
                  <div style={{ fontSize:10, color:B.muted, letterSpacing:2, fontWeight:600 }}>RND {i+1}</div>
                  <div style={{ fontSize:24, fontWeight:900, color:ss.color }}>{s}</div>
                </div>
              );})}
            </div>
          </div>

          <div style={{ display:"grid", gap:9 }}>
            <button onClick={()=>{setRoundIdx(0);setScores([]);setScreen("briefing");}} style={{ padding:"14px", background:B.red, border:"none", borderRadius:10, color:B.white, fontSize:13, fontWeight:800, cursor:"pointer", letterSpacing:2, fontFamily:B.font, boxShadow:`0 4px 18px ${rgba(B.red,0.3)}` }}>
              🔁 REPLAY PACK
            </button>
            <button onClick={()=>setScreen("home")} style={{ padding:"14px", background:rgba(B.white,0.04), border:`1px solid ${rgba(B.white,0.1)}`, borderRadius:10, color:"#ddd", fontSize:13, fontWeight:700, cursor:"pointer", letterSpacing:2, fontFamily:B.font }}>
              ← CHOOSE ANOTHER PACK
            </button>
          </div>
        </div>
      </Shell>
    );
  }

  return null;
}
